import { Config } from '@/store/_config';
import { Reader } from '@/store/_reader';
import type { ReadChapter } from '@/types';
import { stringifyError } from '@/utils/errors';
import axios from 'axios';
import { LRUCache } from 'lru-cache';
import { useCallback, useEffect, useState } from 'react';
import { useSelector } from 'react-redux';

const cache = new LRUCache<string, Promise<ReadChapter>>({ max: 1000 });

async function fetchChapter(
  chapterId: string,
  language?: string,
  autoFetch?: boolean
): Promise<ReadChapter> {
  const key = `${chapterId}:${language}:${autoFetch}`;
  const { data } = await axios.get<ReadChapter>(
    `/api/chapter/${chapterId}/read`,
    {
      params: {
        language,
        auto_fetch: autoFetch,
      },
    }
  );
  cache.set(key, Promise.resolve(data));
  return data;
}

async function fetchChapterCached(
  chapterId: string,
  language?: string,
  autoFetch?: boolean
): Promise<ReadChapter> {
  const key = `${chapterId}:${language}:${autoFetch}`;
  let promise = cache.get(key);
  if (!promise) {
    promise = fetchChapter(chapterId, language, autoFetch);
    promise.catch(() => cache.delete(key));
    cache.set(key, promise);
  }
  return promise;
}

export function useChapterPreloader(chapterId?: string, language?: string) {
  const autoFetch = useSelector(Reader.select.autoFetch);
  const chapterFetchPollIntervalMs = useSelector(
    Config.select.chapterFetchPollIntervalMs
  );
  const readerPreloadNextChapter = useSelector(
    Config.select.readerPreloadNextChapter
  );
  const readerPreloadPreviousChapter = useSelector(
    Config.select.readerPreloadPreviousChapter
  );

  const [refreshId, setRefreshId] = useState(0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string>();
  const [current, setCurrent] = useState<ReadChapter>();

  // current chapter content data
  useEffect(() => {
    if (!chapterId) {
      queueMicrotask(() => {
        setLoading(false);
        setCurrent(undefined);
        setError('No chapter ID in URL');
      });
      return;
    }
    queueMicrotask(async () => {
      setLoading(true);
      setError(undefined);
      try {
        const data = await fetchChapterCached(chapterId, language, autoFetch);
        setCurrent(data);
      } catch (err) {
        setError(stringifyError(err));
      } finally {
        setLoading(false);
      }
    });
  }, [chapterId, language, autoFetch, refreshId]);

  // preload next chapter
  useEffect(() => {
    if (readerPreloadNextChapter && current?.next_id) {
      void fetchChapterCached(current.next_id, language);
    }
  }, [language, current?.next_id, readerPreloadNextChapter]);

  // preload previous chapter
  useEffect(() => {
    if (readerPreloadPreviousChapter && current?.previous_id) {
      void fetchChapterCached(current.previous_id, language);
    }
  }, [language, current?.previous_id, readerPreloadPreviousChapter]);

  // Polls fetch job status and refreshes chapter when job is done
  useEffect(() => {
    if (!chapterId || !autoFetch || !current?.job || current.job.is_done) {
      return;
    }
    const iid = setInterval(
      () => {
        fetchChapter(chapterId, language, autoFetch)
          .then(setCurrent)
          .catch(console.debug);
      },
      Math.max(300, chapterFetchPollIntervalMs)
    );
    return () => clearInterval(iid);
  }, [
    chapterId,
    language,
    autoFetch,
    current?.job,
    chapterFetchPollIntervalMs,
  ]);

  /// Refresh chapter content
  const refresh = useCallback(() => {
    setRefreshId((v) => v + 1);
  }, []);

  return {
    error,
    loading,
    refresh,
    data: current,
    job: current?.job,
  };
}
