import type { LanguageCode, ReadChapter } from '@/types';
import { Flex, Skeleton, Typography } from 'antd';
import { Link } from 'react-router-dom';

export const ReaderTitleBar: React.FC<{
  data: ReadChapter | undefined;
  language?: LanguageCode;
}> = ({ data, language }) => {
  return (
    <Flex gap={4} vertical align="center" justify="center">
      <Typography.Title level={4} style={{ margin: 0, color: '#F16C6F' }}>
        {data?.novel.authors ?? (
          <Skeleton
            active
            paragraph={false}
            styles={{
              root: { width: 300 },
              title: { margin: 0, height: 20 },
            }}
          />
        )}
      </Typography.Title>
      <Typography.Title level={1} style={{ margin: 0 }}>
        {data?.novel.id ? (
          <Link
            to={`/novel/${data.novel.id}${language ? `/${language}` : ''}`}
            style={{ color: '#8484F4' }}
          >
            {data.novel.title}
          </Link>
        ) : (
          <Skeleton
            active
            paragraph={false}
            styles={{
              root: { width: 400 },
              title: { margin: 0, height: 35 },
            }}
          />
        )}
      </Typography.Title>
    </Flex>
  );
};
