import './fonts.css';
import './NovelReader.scss';

import cx from 'classnames';
import styles from './layout.module.scss';

import { store } from '@/store';
import { Reader } from '@/store/_reader';
import { Button, Divider, Empty, Flex, Grid, Result, Spin } from 'antd';
import { useEffect } from 'react';
import { useSelector } from 'react-redux';
import { useParams } from 'react-router-dom';
import { JobDetailsCard } from '../JobDetails/JobDetailsCard';
import { ReaderContent } from './ReaderContent';
import { ReaderNavBar } from './ReaderNavBar';
import { ReaderTitleBar } from './ReaderTitleBar';
import { useChapterPreloader } from './useChapterPreloader';
import { useWakeLock } from './useWakeLock';

export const NovelReader: React.FC<any> = () => {
  useWakeLock();
  const { md } = Grid.useBreakpoint();
  const theme = useSelector(Reader.select.theme);
  const fontSize = useSelector(Reader.select.fontSize);
  const lineHeight = useSelector(Reader.select.lineHeight);
  const fontFamily = useSelector(Reader.select.fontFamily);
  const autoFetch = useSelector(Reader.select.autoFetch);

  const { id, language } = useParams<{ id: string; language?: string }>();
  const { data, job, loading, error, refresh } = useChapterPreloader(
    id,
    language
  );

  // Reset scroll position and speaking position when chapter is loaded
  useEffect(() => {
    if (!data) return;

    // reset scroll position
    window.scrollTo(0, 0);

    // reset speaking position
    store.dispatch(Reader.action.setSepakPosition(0));
  }, [data]);

  return (
    <Flex
      vertical
      className={cx('novel-reader', styles.layout, {
        [styles.mobile]: !md,
      })}
      style={{
        fontSize,
        lineHeight,
        fontFamily,
        ...theme,
      }}
    >
      <ReaderTitleBar data={data} language={language} />
      <Divider size="middle" style={{ background: theme.color + '44' }} />
      <ReaderNavBar data={data} />

      {job ? (
        <div className={styles.expanded}>
          <JobDetailsCard job={job} />
          <Button href={`/job/${job.id}`}>View Request</Button>
        </div>
      ) : loading ? (
        <div className={styles.expanded}>
          <Spin size="large" style={{ margin: 0 }} />
        </div>
      ) : error || !id ? (
        <div className={styles.expanded}>
          <Result
            status="404"
            title="Failed to load chapter content"
            subTitle={error}
            extra={<Button onClick={refresh}>Retry</Button>}
          />
        </div>
      ) : data?.content ? (
        <ReaderContent data={data} />
      ) : (
        <div className={styles.expanded}>
          <Empty
            description="No contents available"
            styles={{ description: { color: theme.color } }}
          />
          {!autoFetch && (
            <Button
              onClick={() => store.dispatch(Reader.action.setAutoFetch(true))}
            >
              Enable Auto Fetch
            </Button>
          )}
        </div>
      )}
    </Flex>
  );
};
