import cx from 'classnames';
import styles from './layout.module.scss';

import { API_BASE_URL } from '@/config';
import { store } from '@/store';
import { Auth } from '@/store/_auth';
import { Reader } from '@/store/_reader';
import type { ReadChapter } from '@/types';
import {
  memo,
  useCallback,
  useEffect,
  useLayoutEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import { renderToStaticMarkup } from 'react-dom/server';
import { useSelector } from 'react-redux';
import { useNavigate, useParams } from 'react-router-dom';
import { getVoices } from '../SettingsPage/ReaderSettings/VoiceSettings';
import { ChapterHeader } from './ChapterHeader';

const CONTENT_CLEANER_REGEX = /<p>(\s+)|(&nbsp;)+<\/p>(\n|\s|<br\/>)+/gim;

export const ReaderContent: React.FC<{
  data: ReadChapter;
}> = memo(({ data }) => {
  const navigate = useNavigate();
  const contentRef = useRef<HTMLDivElement | null>(null);
  const { language } = useParams<{ language?: string }>();

  const token = useSelector(Auth.select.authToken);
  const voiceName = useSelector(Reader.select.voice);
  const speaking = useSelector(Reader.select.speaking);
  const textAlign = useSelector(Reader.select.textAlign);
  const position = useSelector(Reader.select.speakPosition);
  const voiceSpeed = useSelector(Reader.select.voiceSpeed);
  const voicePitch = useSelector(Reader.select.voicePitch);

  const [loading, setLoading] = useState<boolean>(true);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [currentText, setCurrentText] = useState<string | null>(null);

  const voice = useMemo(
    () => voices.find((x) => x.name === voiceName) || voices[0],
    [voices, voiceName]
  );

  const content = useMemo(() => {
    if (!token || !data.content) return;

    const parser = new DOMParser();

    const clean = data.content!.replace(CONTENT_CLEANER_REGEX, '');
    const doc = parser.parseFromString(clean, 'text/html');

    // prepend header
    const header = renderToStaticMarkup(<ChapterHeader data={data} />);
    const headerDoc = parser.parseFromString(header, 'text/html');
    doc.body.prepend(...headerDoc.body.children);

    // replace image urls
    for (const img of doc.querySelectorAll('img')) {
      if (!img.src.includes(img.alt)) continue;
      img.src = `${API_BASE_URL}/static/novels/${data.novel.id}/images/${img.alt}.jpg?token=${token}`;
      img.loading = 'lazy';
    }

    return doc;
  }, [data, token]);

  // Load available TTS voices and cancel speech on page unload
  useEffect(() => {
    getVoices()
      .then(setVoices)
      .finally(() => setLoading(false));

    const aborter = new AbortController();
    window.addEventListener(
      'beforeunload',
      () => {
        window.speechSynthesis.cancel();
        store.dispatch(Reader.action.setSpeaking(false));
      },
      { signal: aborter.signal }
    );
    return () => aborter.abort();
  }, []);

  // Navigate to next chapter (or stop speaking) when position passes the last element
  useEffect(() => {
    if (!speaking || !content) return;
    if (position < content.body.children.length) return;
    if (data.next_id) {
      navigate(`/read/${data.next_id}${language ? `/${language}` : ''}`);
    } else {
      store.dispatch(Reader.action.setSpeaking(false));
    }
    store.dispatch(Reader.action.setSepakPosition(0));
  }, [data.next_id, content, speaking, position, language, navigate]);

  // Resolve text at the current position; skip aria-hidden/empty nodes by incrementing
  useEffect(() => {
    if (!speaking || !content) return;
    if (position >= content.body.children.length) return;
    const childEl = content.body.children[position];
    const text = childEl.textContent;
    const isAriaHidden = childEl.getAttribute('aria-hidden') === 'true';
    if (!text || isAriaHidden) {
      store.dispatch(Reader.action.incrementSepakPosition());
    } else {
      queueMicrotask(() => setCurrentText(text));
    }
    return () => setCurrentText(null);
  }, [content, speaking, position]);

  // Speak text from current position, and move to next when done
  useEffect(() => {
    if (loading || !speaking || !currentText || !voice) return;

    const utterance = new SpeechSynthesisUtterance(currentText);
    utterance.voice = voice;
    utterance.rate = voiceSpeed;
    utterance.pitch = voicePitch;

    utterance.addEventListener('end', () => {
      store.dispatch(Reader.action.incrementSepakPosition());
    });

    const tid = setTimeout(() => {
      window.speechSynthesis.speak(utterance);
    }, 50);

    return () => {
      clearTimeout(tid);
      requestAnimationFrame(() => {
        window.speechSynthesis.cancel();
      });
    };
  }, [loading, speaking, currentText, voice, voiceSpeed, voicePitch]);

  // Stamp chapter HTML into the DOM once per content change (before paint to avoid flash)
  useLayoutEffect(() => {
    if (!contentRef.current) return;
    contentRef.current.innerHTML = content?.body.innerHTML || '';
  }, [content]);

  // Track the active paragraph for scroll-into-view and CSS highlight
  useLayoutEffect(() => {
    if (!contentRef.current) return;
    const current = contentRef.current.children[position];
    current?.setAttribute('data-focus', 'true');
    return () => current?.removeAttribute('data-focus');
  }, [content, position]);

  const handleClick = useCallback((e: React.MouseEvent<HTMLElement>) => {
    let target = e.target as HTMLElement | null;
    if (!contentRef.current || !contentRef.current.contains(target)) return;
    while (target && target.parentElement !== contentRef.current) {
      target = target.parentElement!;
    }
    if (target) {
      const index = Array.prototype.indexOf.call(
        contentRef.current.children,
        target
      );
      store.dispatch(Reader.action.setSepakPosition(index));
    }
  }, []);

  return (
    <div
      ref={contentRef}
      id="chapter-content"
      onPointerUp={handleClick}
      className={cx(styles.content, {
        [styles.speaking]: speaking,
      })}
      style={{
        textAlign: textAlign as any,
        direction: textAlign === 'right' ? 'rtl' : 'ltr',
      }}
    />
  );
});
