import { type ReadChapter } from '@/types';
import { formatFromNow, formatNumber } from '@/utils/formatter';
import { memo } from 'react';

export const ChapterHeader = memo<{ data: ReadChapter }>(({ data }) => {
  return (
    <>
      <h1 style={{ marginBottom: 6 }}>{data.chapter.title.trim()}</h1>
      <div
        aria-hidden="true"
        aria-disabled="true"
        style={{
          fontSize: 12,
          opacity: 0.8,
          marginBottom: 25,
          direction: 'ltr',
        }}
      >
        <span>
          {data.chapter.serial} of {data.novel.chapter_count}
        </span>
        <span> | </span>
        <span>Updated {formatFromNow(data.chapter.updated_at)}</span>
        {data.word_count && (
          <>
            <span> | </span>
            <span>{formatNumber(data.word_count, 0)} words</span>
          </>
        )}
      </div>
    </>
  );
});
